{"document": {"aggregate_severity": {"namespace": "https://access.redhat.com/security/updates/classification/", "text": "Important"}, "category": "csaf_security_advisory", "csaf_version": "2.0", "distribution": {"text": "Copyright © Red Hat, Inc. All rights reserved.", "tlp": {"label": "WHITE", "url": "https://www.first.org/tlp/"}}, "lang": "en", "notes": [{"category": "summary", "text": "A new satellite/iop-remediations-rhel9 container image is now generally available in the Red Hat container registry.", "title": "Topic"}, {"category": "general", "text": "Red Hat Lightspeed in Satellite analyzes system health and configuration by applying  predefined rules to a small set of local data, such as installed packages,  running services, and configuration settings.  When you install Red Hat Lightspeed in Satellite locally,  you can generate Red Hat Lightspeed recommendations without  sending system data to Red Hat services. ", "title": "Details"}, {"category": "legal_disclaimer", "text": "This content is licensed under the Creative Commons Attribution 4.0 International License (https://creativecommons.org/licenses/by/4.0/). If you distribute this content, or a modified version of it, you must provide attribution to Red Hat Inc. and provide a link to the original.", "title": "Terms of Use"}], "publisher": {"category": "vendor", "contact_details": "https://access.redhat.com/security/team/contact/", "issuing_authority": "Red Hat Product Security is responsible for vulnerability handling across all Red Hat products and services.", "name": "Red Hat Product Security", "namespace": "https://www.redhat.com"}, "references": [{"category": "self", "summary": "https://access.redhat.com/errata/RHSA-2026:6288", "url": "https://access.redhat.com/errata/RHSA-2026:6288"}, {"category": "external", "summary": "https://access.redhat.com/documentation/en-us/red_hat_satellite/6.18/html/updating_red_hat_satellite/index", "url": "https://access.redhat.com/documentation/en-us/red_hat_satellite/6